using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
const int N=1e6+5;
struct P{int x,y;bool operator<(const P&t)const{return x<t.x;}}e[N<<1];
int n,m,i,w,ans,l;
signed main()
{
	n=read();m=read();
	for(i=0;i<n;++i)
	{
		l=read();e[i<<1].x=w;
		if(getchar()=='L')
		{
			e[i<<1].y=-1;
			e[i<<1|1]=(P){w-=l,+1};
		}
		else
		{
			e[i<<1].y=+1;
			e[i<<1|1]=(P){w+=l,-1};
		}
	}
	sort(e,e+(n<<1));
	w=e[0].y;
	for(i=0;i+1<n<<1;w+=e[++i].y)
		if(w>=m)ans+=e[i+1].x-e[i].x;
	writeln(ans);
	return 0;
}
